  trustEncrypted: "Encrypted",
  trustSynced: "Progress synced",
})

function clearSlowHintTimer() {
  if (slowHintTimer !== undefined) {
    window.clearTimeout(slowHintTimer)
    slowHintTimer = undefined
  }
}

async function loginWithGfi() {
  if (loginState.value === "loading") return

  clearSlowHintTimer()
  loginState.value = "loading"
  showSlowHint.value = false
  slowHintTimer = window.setTimeout(() => {
    showSlowHint.value = true
  }, 3000)

  try {
    const callbackUrl = encodeURIComponent(`${window.location.origin}/callback`)
    const resData = await apiClient(`/api/auth/login-url?callback=${callbackUrl}`)
    if (!resData?.url) throw new Error("AUTH_LOGIN_URL_MISSING")
    window.location.assign(resData.url)
  } catch (error) {
    console.error("Unable to start GFI login:", error)
    clearSlowHintTimer()
    showSlowHint.value = false
    loginState.value = "error"
  }
}

onBeforeUnmount(clearSlowHintTimer)
