    <section class="auth-panel" :class="{ 'english-auth': lang === 'en' }" :aria-label="copy.authAria">
      <div class="auth-toolbar">
        <div class="mobile-brand" aria-hidden="true">
          <svg class="gfi-logo" viewBox="0 0 1734 897"><use href="#login-gfi-logo" /></svg>
        </div>
        <div class="language-switch" role="group" :aria-label="copy.languageAria">
          <button type="button" :class="{ active: lang === 'zh' }" :aria-pressed="lang === 'zh'" @click="changeLanguage('zh')">中文</button>
          <button type="button" :class="{ active: lang === 'en' }" :aria-pressed="lang === 'en'" @click="changeLanguage('en')">EN</button>
        </div>
      </div>

      <div class="auth-content">
        <div v-if="lang === 'en'" class="auth-access entrance entrance-1">
          <span class="auth-access-icon" aria-hidden="true"><ShieldCheck :size="17" :stroke-width="1.7" /></span>
          <span><strong>{{ copy.secureAccess }}</strong><small>{{ copy.secureAccessSub }}</small></span>
        </div>

        <div class="login-card entrance entrance-2" :data-state="loginState">
          <h2>{{ copy.welcome }}</h2>
          <p class="card-subtitle">{{ copy.subtitle }}</p>

          <div v-if="loginState === 'error'" class="error-message" role="alert">
            <AlertCircle :size="17" aria-hidden="true" />
            <div>
              <strong>{{ copy.errorTitle }}</strong>
              <span>{{ copy.errorDescription }}</span>
            </div>
            <button type="button" @click="loginWithGfi">{{ copy.retry }}</button>
          </div>

          <button class="login-button" type="button" :disabled="loginState === 'loading'" @click="loginWithGfi">
            <span>{{ loginState === "loading" ? copy.loading : copy.login }}</span>
            <ArrowRight v-if="loginState !== 'loading'" :size="18" :stroke-width="2.2" aria-hidden="true" />
            <i v-else aria-hidden="true" />
          </button>

          <p class="secure-note">
            <LockKeyhole :size="14" :stroke-width="1.8" aria-hidden="true" />
            <span>{{ copy.secure }}</span>
          </p>
          <p v-if="showSlowHint" class="slow-hint" role="status" aria-live="polite">{{ copy.slow }}</p>
        </div>

        <div v-if="lang === 'en'" class="auth-trust entrance entrance-3" :aria-label="copy.secureAccess">
          <span>{{ copy.trustOfficial }}</span>
          <span>{{ copy.trustEncrypted }}</span>
          <span>{{ copy.trustSynced }}</span>
        </div>
      </div>
    </section>
  </main>
</template>

<style scoped>
.login-page {
  --brand: #1b458d;
  --brand-deep: #123063;
