  --line: #d6dee9;
  --gold: #c9962e;
  display: flex;
  min-height: 100vh;
  overflow: hidden;
  background: var(--background);
  color: var(--ink);
  font-family: -apple-system, BlinkMacSystemFont, "PingFang SC", "Helvetica Neue", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
}

.login-page *,
.login-page *::before,
.login-page *::after {
  box-sizing: border-box;
}

button {
  border: 0;
  font: inherit;
}

.svg-definitions {
  position: absolute;
  width: 0;
  height: 0;
  overflow: hidden;
}

.brand-panel {
  position: relative;
  display: flex;
  flex: 0 0 55%;
  min-width: 0;
  overflow: hidden;
  color: white;
  background: linear-gradient(135deg, var(--brand-deep) 0%, var(--brand) 55%, var(--brand-mid) 100%);
}

.brand-glow {
  position: absolute;
  inset: -25% -15%;
